  PROXY: 0,      // ProRes 422 Proxy (~45 Mbps @ 1080p30)
  LT: 1,         // ProRes 422 LT (~102 Mbps @ 1080p30)
  STANDARD: 2,   // ProRes 422 Standard (~147 Mbps @ 1080p30)
  HQ: 3,         // ProRes 422 HQ (~220 Mbps @ 1080p30)
  P4444: 4,      // ProRes 4444 (~330 Mbps @ 1080p30)
